EM_SETREADONLY=0x00CF
CLASS_NAME="AnyGameAIInstallerClass"
main_hwnd=None
font=None
path_edit=None
status_text=None
browse_button=None
confirm_button=None
install_button=None
finish_button=None
confirmed=False
installed=False
ctypes.WinDLL("gdi32",use_last_error=True).GetStockObject.restype=wt.HANDLE

def loword(v):
    return int(v)&0xffff

def message(text,title="AnyGameAI 安装程序",flags=MB_OK|MB_ICONINFORMATION):
    return user32.MessageBoxW(main_hwnd,str(text),title,flags)

def set_text(hwnd,text):
    user32.SetWindowTextW(hwnd,str(text))

def get_text(hwnd):
    n=user32.GetWindowTextLengthW(hwnd)
    b=ctypes.create_unicode_buffer(n+1)
    user32.GetWindowTextW(hwnd,b,n+1)
    return b.value

def child(cls,text,style,x,y,w,h,cid):
    hwnd=user32.CreateWindowExW(0,cls,text,style,x,y,w,h,main_hwnd,ctypes.c_void_p(cid),kernel32.GetModuleHandleW(None),None)
    user32.SendMessageW(hwnd,WM_SETFONT,font,1)
    return hwnd

def browse():
    global confirmed
    display=ctypes.create_unicode_buffer(32768)
    bi=BROWSEINFO()
    bi.hwndOwner=main_hwnd
    bi.pszDisplayName=display
    bi.lpszTitle="选择 AnyGameAI 的安装位置"
    bi.ulFlags=0x0001|0x0040
    pidl=shell32.SHBrowseForFolderW(ctypes.byref(bi))
    if pidl:
        try:
            path=ctypes.create_unicode_buffer(32768)
            if shell32.SHGetPathFromIDListW(pidl,path):
                set_text(path_edit,path.value)
                set_text(status_text,"已选择安装位置，请点击“确认”。")
                confirmed=False
                user32.EnableWindow(confirm_button,True)
                user32.EnableWindow(install_button,False)
        finally:
            ole32.CoTaskMemFree(pidl)

def destination(root):
    root=os.path.abspath(os.path.expandvars(os.path.expanduser(root)))
    if os.path.basename(os.path.normpath(root)).lower()=="anygameai":
        return root
    return os.path.join(root,"AnyGameAI")

def confirm_path():
    global confirmed
    root=get_text(path_edit).strip()
    if not root:
        raise RuntimeError("请先点击“浏览”选择安装位置。")
    if not os.path.isdir(root):
        raise RuntimeError("所选安装位置不存在或不是文件夹。")
    dest=destination(root)
    set_text(status_text,"安装位置已确认："+dest)
    confirmed=True
    user32.EnableWindow(path_edit,False)
    user32.EnableWindow(browse_button,False)
    user32.EnableWindow(confirm_button,False)
    user32.EnableWindow(install_button,True)

def install():
    global installed
    if not confirmed:
        raise RuntimeError("请先确认安装位置。")
    root=get_text(path_edit).strip()
    dest=destination(root)
    if os.path.exists(dest):
        if message("目标文件夹已经存在。是否覆盖该文件夹？","确认",MB_YESNO|MB_ICONINFORMATION)!=IDYES:
            return
    set_text(status_text,"正在安装……")
    user32.EnableWindow(install_button,False)
    user32.UpdateWindow(main_hwnd)
    raw=zlib.decompress(base64.b64decode(PAYLOAD))
    if hashlib.sha256(raw).hexdigest()!=EXPECTED:
        raise RuntimeError("安装数据校验失败。")
    temp=dest+".installing"
    if os.path.exists(temp):
        shutil.rmtree(temp)
    os.makedirs(temp)
    try:
        exe=os.path.join(temp,"AnyGameAI.exe")
        with open(exe,"wb") as f:
            f.write(raw)
            f.flush()
            os.fsync(f.fileno())
        os.makedirs(os.path.join(temp,"data"),exist_ok=True)
        if os.path.exists(dest):
            shutil.rmtree(dest)
        os.replace(temp,dest)
    except Exception:
        if os.path.exists(temp):
            shutil.rmtree(temp,ignore_errors=True)
        raise
    installed=True
    set_text(status_text,"安装成功。请点击“完成”关闭安装窗口。")
    user32.EnableWindow(finish_button,True)
    message("安装成功。","AnyGameAI 安装程序",MB_OK|MB_ICONINFORMATION)

def show_error():
    text=traceback.format_exc()
    user32.MessageBoxW(main_hwnd,text,"报错",MB_OK|MB_ICONERROR)
    if confirmed and not installed:
        user32.EnableWindow(install_button,True)

def wndproc(hwnd,msg,wparam,lparam):
    try:
        if msg==WM_COMMAND:
            cid=loword(wparam)
            if cid==101:
                browse()
            elif cid==102:
                confirm_path()
            elif cid==103:
                install()
            elif cid==104:
                user32.DestroyWindow(hwnd)
            return 0
        if msg==WM_CLOSE:
            user32.DestroyWindow(hwnd)
            return 0
        if msg==WM_DESTROY:
            user32.PostQuitMessage(0)
            return 0
    except Exception:
        show_error()
    return user32.DefWindowProcW(hwnd,msg,wparam,lparam)

_wndproc=WNDPROC(wndproc)

def main():
    global main_hwnd,font,path_edit,status_text,browse_button,confirm_button,install_button,finish_button
    if os.name!="nt":
        raise OSError("此安装程序只能在 Windows 11 上运行。")
    hinst=kernel32.GetModuleHandleW(None)
    gdi32=ctypes.WinDLL("gdi32",use_last_error=True)
    font=gdi32.GetStockObject(DEFAULT_GUI_FONT)
    wc=WNDCLASSW()
    wc.lpfnWndProc=_wndproc
    wc.hInstance=hinst
    wc.hCursor=user32.LoadCursorW(None,ctypes.cast(ctypes.c_void_p(IDC_ARROW),wt.LPCWSTR))
    wc.hbrBackground=wt.HBRUSH(COLOR_WINDOW+1)
    wc.lpszClassName=CLASS_NAME
    atom=user32.RegisterClassW(ctypes.byref(wc))
    if not atom and ctypes.get_last_error()!=1410:
        raise ctypes.WinError(ctypes.get_last_error())
    w,h=700,360
    x=(user32.GetSystemMetrics(0)-w)//2
    y=(user32.GetSystemMetrics(1)-h)//2
    main_hwnd=user32.CreateWindowExW(0,CLASS_NAME,"AnyGameAI 安装程序",WS_CAPTION|WS_SYSMENU|WS_MINIMIZEBOX,x,y,w,h,None,None,hinst,None)
    if not main_hwnd:
        raise ctypes.WinError(ctypes.get_last_error())
    child("STATIC","AnyGameAI 安装程序",WS_CHILD|WS_VISIBLE,28,24,360,30,0)
    child("STATIC","安装位置",WS_CHILD|WS_VISIBLE,28,73,100,24,0)
    path_edit=child("EDIT","",WS_CHILD|WS_VISIBLE|WS_BORDER|WS_TABSTOP,28,101,520,30,100)
    browse_button=child("BUTTON","浏览",WS_CHILD|WS_VISIBLE|WS_TABSTOP,564,101,95,30,101)
    confirm_button=child("BUTTON","确认",WS_CHILD|WS_VISIBLE|WS_TABSTOP,352,158,95,34,102)
    install_button=child("BUTTON","安装",WS_CHILD|WS_VISIBLE|WS_TABSTOP,458,158,95,34,103)
    finish_button=child("BUTTON","完成",WS_CHILD|WS_VISIBLE|WS_TABSTOP,564,158,95,34,104)
    status_text=child("EDIT","请点击“浏览”选择安装位置。",WS_CHILD|WS_VISIBLE|WS_BORDER|ES_READONLY,28,220,631,52,105)
    user32.EnableWindow(confirm_button,False)
    user32.EnableWindow(install_button,False)
    user32.EnableWindow(finish_button,False)
    user32.ShowWindow(main_hwnd,SW_SHOW)
    user32.UpdateWindow(main_hwnd)
    msg=MSG()
    while user32.GetMessageW(ctypes.byref(msg),None,0,0)>0:
        user32.TranslateMessage(ctypes.byref(msg))
        user32.DispatchMessageW(ctypes.byref(msg))

main()
